var body = $json.body || $json;
var findings = body.findings || [];
var requirements = body.requirements || {};
var procurementInfo = body.procurementInfo || {};

// Filter only non-compliant findings for legal review
var nonCompliant = findings.filter(function(f) {
  return f.status !== 'COMPLIANT';
});

var procStr = JSON.stringify(procurementInfo, null, 2).substring(0, 3000);
var reqStr = JSON.stringify(requirements, null, 2).substring(0, 20000);
var findingsStr = JSON.stringify(nonCompliant, null, 2).substring(0, 40000);

var p = 'Ти си юрист-експерт по обществени поръчки в България с дълбоки познания по ЗОП, ППЗОП, и практиката на КЗК и ВАС.\n\n';
p += '## ЗАДАЧА\n';
p += 'Прегледай констатациите от проверка на техническо предложение и ги валидирай юридически.\n\n';
p += '## ДАННИ ЗА ПОРЪЧКАТА:\n' + procStr + '\n\n';
p += '## ИЗИСКВАНИЯ ОТ ДОКУМЕНТАЦИЯТА:\n' + reqStr + '\n\n';
p += '## КОНСТАТАЦИИ ЗА НЕСЪОТВЕТСТВИЯ (' + nonCompliant.length + ' бр.):\n' + findingsStr + '\n\n';
p += '## ЗА ВСЯКА КОНСТАТАЦИЯ ОПРЕДЕЛИ:\n\n';
p += '### 1. ПРАВНО ОСНОВАНИЕ\n';
p += '- Кой конкретен текст от документацията е нарушен\n';
p += '- Приложими членове от ЗОП (особено чл. 107, ал. 1 и ал. 2)\n';
p += '- Приложими текстове от ППЗОП\n';
p += '- Съответна практика на КЗК ако е релевантна\n\n';
p += '### 2. КВАЛИФИКАЦИЯ\n';
p += '- Задължително изискване ли е (води до отстраняване)?\n';
p += '- Или оценяемо (води до по-ниски точки)?\n';
p += '- Може ли да се поиска разяснение по чл. 104, ал. 5 ЗОП?\n';
p += '- Има ли право на отстраняване на нередовности по чл. 104, ал. 7 ЗОП?\n\n';
p += '### 3. РИСК ОТ ОБЖАЛВАНЕ ПРЕД КЗК\n';
p += '- Каква е вероятността за успешно обжалване от кандидата?\n';
p += '- Какви аргументи може да използва кандидатът?\n';
p += '- Какви контрааргументи има комисията?\n\n';
p += '### 4. ПРЕПОРЪКА\n';
p += '- DISQUALIFY: Ясно и безспорно нарушение — достатъчно за отстраняване\n';
p += '- REQUEST_CLARIFICATION: Изискване на разяснения по чл. 104, ал. 5 ЗОП\n';
p += '- REDUCE_POINTS: Непълно покритие на оценяем критерий\n';
p += '- NO_VIOLATION: Констатацията НЕ е достатъчно силна юридически\n\n';
p += '## КРИТИЧНИ ПРАВИЛА\n';
p += '- Бъди КОНСЕРВАТИВЕН — препоръчвай отстраняване САМО при ясно и безспорно нарушение\n';
p += '- Посочвай КОНКРЕТНИ членове и алинеи от ЗОП/ППЗОП\n';
p += '- НЕ измисляй правни норми — САМО реални текстове от ЗОП/ППЗОП\n';
p += '- При съмнение — препоръчай запитване, НЕ отстраняване\n';
p += '- Всяко заключение трябва да устои на обжалване пред КЗК\n';
p += '- Разграничавай между формална нередовност и съществено нарушение\n\n';
p += '## ФОРМАТ\n';
p += 'Върни САМО валиден JSON:\n';
p += '{\n';
p += '  "validated_findings": [\n';
p += '    {\n';
p += '      "requirement_id": "R1",\n';
p += '      "original_status": "NON_COMPLIANT",\n';
p += '      "legal_assessment": {\n';
p += '        "is_ground_for_disqualification": true,\n';
p += '        "legal_basis": ["чл. X, ал. Y от ЗОП", "т. Z от документацията"],\n';
p += '        "violation_type": "MANDATORY_REQUIREMENT|EVALUATION_CRITERIA|FORMAL_DEFECT",\n';
p += '        "confidence": "HIGH|MEDIUM|LOW",\n';
p += '        "kzk_appeal_risk": "LOW|MEDIUM|HIGH",\n';
p += '        "recommendation": "DISQUALIFY|REQUEST_CLARIFICATION|REDUCE_POINTS|NO_VIOLATION",\n';
p += '        "reasoning": "Подробна юридическа обосновка"\n';
p += '      }\n';
p += '    }\n';
p += '  ],\n';
p += '  "overall_recommendation": {\n';
p += '    "action": "DISQUALIFY|ACCEPT_WITH_REMARKS|ACCEPT",\n';
p += '    "disqualification_grounds_count": 0,\n';
p += '    "high_confidence_grounds": 0,\n';
p += '    "summary": "Обобщение на правния анализ"\n';
p += '  },\n';
p += '  "procedural_notes": ["Процедурни бележки и препоръки за комисията"]\n';
p += '}';

return [{ json: { prompt: p, nonCompliantCount: nonCompliant.length } }];

var raw = ($json.text || $json.response || '').trim();

// Handle error from chainLlm
if ($json.error || $json.errorMessage || (!raw && $input.first().json.error)) {
  return [{ json: {
    legalValidation: {
      validated_findings: [],
      overall_recommendation: {
        action: 'ACCEPT_WITH_REMARKS',
        disqualification_grounds_count: 0,
        summary: 'Legal validation AI error — manual review required'
      },
      procedural_notes: ['AI legal validator encountered an error. All findings require manual legal review.']
    }
  } }];
}

var result;
try {
  result = JSON.parse(raw);
} catch (e) {
  var m = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  var candidate = m ? m[1].trim() : raw;
  try {
    var s = candidate.indexOf('{');
    var e2 = candidate.lastIndexOf('}');
    var js = candidate.substring(s, e2 + 1).replace(/,\s*([\]\}])/g, '$1');
    result = JSON.parse(js);
  } catch (e3) {
    result = {
      validated_findings: [],
      overall_recommendation: {
        action: 'ACCEPT_WITH_REMARKS',
        disqualification_grounds_count: 0,
        summary: 'Parse error — manual review required'
      },
      procedural_notes: ['JSON parse failed. Raw AI response needs manual review.']
    };
  }
}

return [{ json: { legalValidation: result } }];
